def flatten(lst: list) -> list:
    result = []
    for item in lst:
        if isinstance(item, list):
            # Recursively call flatten and extend the result list
            result.extend(flatten(item))
        else:
            # If it's not a list, just append the item
            result.append(item)
    return result

# Example usage:
print(flatten([1, [2, [3, 4], 5]]))  # Output: [1, 2, 3, 4, 5]

def binary_search(arr, target):
    left, right = 0, len(arr) - 1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return -1

